const CustomYAxisTick = (props: YAxisTickContentProps) => {
  const {
    payload: { value },
  } = props;

  let fill: string;
  switch (Math.sign(value)) {
    case -1:
      fill = 'red';
      break;
    case 1:
      fill = 'green';
      break;
    default:
      fill = 'black';
  }

  return (
    <Text {...props} fill={fill} fontWeight={value === 0 ? 'bold' : 'normal'}>
      {value}
    </Text>
  );
};

